// /api/internal - password-gated internal docs (partner brief, revenue model, growth engine + notes).
// Server-side HTTP Basic Auth: the HTML is never sent until the password matches,
// and every document is embedded as base64 so they never exist as public static files.
// Change the password via the INTERNAL_PW env var (then redeploy), or edit FALLBACK_PW.
const FALLBACK_PW = 'ntp-goldrush-26';
const BRIEF = '';
const MODEL = '';
const GROWTH = '';
const GROWTH_NOTES = '';

export default function handler(req, res) {
  const expected = process.env.INTERNAL_PW || FALLBACK_PW;
  const auth = req.headers.authorization || '';
  let ok = false;
  if (auth.startsWith('Basic ')) {
    try {
      const decoded = Buffer.from(auth.slice(6), 'base64').toString('utf8');
      const pass = decoded.slice(decoded.indexOf(':') + 1); // accept any username
      if (pass === expected) ok = true;
    } catch (e) { ok = false; }
  }
  res.setHeader('X-Robots-Tag', 'noindex, nofollow');
  if (!ok) {
    res.setHeader('WWW-Authenticate', 'Basic realm="AI4NTP Internal", charset="UTF-8"');
    res.status(401).send('Authentication required.');
    return;
  }
  const q = req.query && req.query.doc;
  const doc = q === 'model' ? MODEL
            : q === 'growth' ? GROWTH
            : q === 'growth-notes' ? GROWTH_NOTES
            : BRIEF;
  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.setHeader('Cache-Control', 'private, no-store, max-age=0');
  res.status(200).send(Buffer.from(doc, 'base64').toString('utf8'));
}
